@* ───── Security Section ───── *@
@code {
    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h2>Security</h2>
            <p class="section-desc">Manage your password, two-factor authentication, and active sessions.</p>

            <!-- Change Password -->
            <div class="expandable-panel">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="form-group">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <p class="field-error">@_passwordError</p>
                        }
                        <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                            @(_saving ? "Updating…" : "Update Password")
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Auth -->
            <div class="toggle-row" style="margin-top:1.5rem;">
                <div class="toggle-info">
                    <span class="toggle-label">Two-Factor Authentication</span>
                    <span class="toggle-desc">
                        Status:
                        <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </span>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="slider"></span>
                </label>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="text-muted" style="margin-top:0.5rem; font-size:0.85rem;">
                    Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </p>
            }

            <!-- Active Sessions -->
            <h3 class="subsection-title" style="margin-top:2rem;">Active Sessions</h3>
            @if (_sessions.Count == 0)
            {
                <p class="text-muted">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="sessions-table">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                    <td>
                                        @if (session != _sessions[0])
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge-current">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </section>
    };
}

@* ───── Appearance Section ───── *@
@code {
    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Appearance</h2>
            <p class="section-desc">Customize how the application looks and feels.</p>

            <div class="appearance-grid">
                <div class="appearance-options">
                    <!-- Theme -->
                    <div class="form-group">
                        <label class="form-label">Theme</label>
                        <div class="radio-group">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                var t = theme;
                                <label class="radio-item @(_appearanceTheme == t ? "selected" : "")">
                                    <input type="radio" name="theme" value="@t"
                                           checked="@(_appearanceTheme == t)"
                                           @onchange="() => _appearanceTheme = t" />
                                    <span>@t</span>
                                </label>
                            }
                        </div>
                    </div>

                    <!-- Font Size -->
                    <div class="form-group">
                        <label class="form-label">Font Size</label>
                        <div class="radio-group">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                var s = size;
                                <label class="radio-item @(_appearanceFontSize == s ? "selected" : "")">
                                    <input type="radio" name="fontSize" value="@s"
                                           checked="@(_appearanceFontSize == s)"
                                           @onchange="() => _appearanceFontSize = s" />
                                    <span>@s</span>
                                </label>
                            }
                        </div>
                    </div>

                    <!-- Language -->
                    <div class="form-group">
                        <label class="form-label">Language</label>
                        <select class="form-control" @bind="_appearanceLanguage">
                            <option value="en">English</option>
                            <option value="es">Español</option>
                            <option value="fr">Français</option>
                            <option value="de">Deutsch</option>
                            <option value="ja">日本語</option>
                            <option value="zh">中文</option>
                            <option value="pt">Português</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-row">
                        <div class="toggle-info">
                            <span class="toggle-label">Compact Mode</span>
                            <span class="toggle-desc">Reduce spacing and padding throughout the UI</span>
                        </div>
                        <label class="switch">
                            <input type="checkbox" @bind="_appearanceCompact" />
                            <span class="slider"></span>
                        </label>
                    </div>
                </div>

                <!-- Live Preview -->
                <div class="preview-area @GetPreviewClasses()">
                    <h4 class="preview-title">Live Preview</h4>
                    <div class="preview-card">
                        <h5>Sample Card</h5>
                        <p>This is how your content will look with the selected settings.</p>
                        <div class="preview-actions">
                            <button class="btn btn-primary btn-sm">Primary</button>
                            <button class="btn btn-secondary btn-sm">Secondary</button>
                        </div>
                    </div>
                    <div class="preview-meta">
                        Theme: @_appearanceTheme · Font: @_appearanceFontSize · Compact: @(_appearanceCompact ? "On" : "Off")
                    </div>
                </div>
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>
        </section>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_appearanceTheme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_appearanceFontSize.ToLowerInvariant()}");
        if (_appearanceCompact) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }
}

@* ───── State & Logic ───── *@
@code {
    // Navigation
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨"),
    };

    // General
    private bool _loading = true;
    private bool _saving;
    private string _toastMessage = "";
    private bool _toastVisible;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notifications
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeekly;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new() { "general", "announcements", "random", "engineering", "design", "marketing" };

    // Security
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string _passwordError = "";
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = new();
    private bool _showRevokeDialog;
    private string _revokeSessionId = "";
    private string _revokeSessionDevice = "";
    private string _revokeSessionLocation = "";

    // Appearance
    private string _appearanceTheme = "Light";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "en";
    private bool _appearanceCompact;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfileToFields(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifWeekly = notif.WeeklyDigest;
        _mutedChannels = new HashSet<string>(notif.MutedChannels);

        // Security
        _securitySettings = securityTask.Result;
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
        _sessions = new List<ActiveSession>(_securitySettings.Sessions);

        // Appearance
        var appearance = appearanceTask.Result;
        _appearanceTheme = appearance.Theme;
        _appearanceFontSize = appearance.FontSize;
        _appearanceLanguage = appearance.Language;
        _appearanceCompact = appearance.CompactMode;
    }

    private void ApplyProfileToFields(UserProfile profile)
    {
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private void SetActiveSection(string section)
    {
        ActiveSection = section;
    }

    // ── Profile actions ──

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var profile = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            await ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error saving profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfileToFields(_savedProfile);
        }
    }

    // ── Notification actions ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeekly, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            await ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security actions ──

    private async Task UpdatePassword()
    {
        _passwordError = "";

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            await ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private void RequestRevoke(ActiveSession session)
    {
        _revokeSessionId = session.Id;
        _revokeSessionDevice = session.Device;
        _revokeSessionLocation = session.Location;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
    }

    private async Task ConfirmRevoke()
    {
        _showRevokeDialog = false;
        try
        {
            await SettingsService.RevokeSessionAsync(_revokeSessionId);
            _sessions.RemoveAll(s => s.Id == _revokeSessionId);
            await ShowToast("Session revoked.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error: {ex.Message}", isError: true);
        }
    }

    // ── Appearance actions ──

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            await ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToast($"Error: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Toast helper ──

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }
}

/* ══════════════════════════════════════
   Settings Dashboard – Scoped Styles
   ══════════════════════════════════════ */

/* ── Layout ── */
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    gap: 0;
}

.settings-sidebar {
    width: 240px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.settings-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-size: 0.95rem;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #e9ecef;
}

.settings-nav-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

/* ── Content area ── */
.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 900px;
    position: relative;
}

.settings-section h2 {
    margin: 0 0 0.25rem;
    font-size: 1.5rem;
    font-weight: 600;
}

.section-desc {
    color: #6c757d;
    margin-bottom: 1.75rem;
}

.subsection-title {
    font-size: 1.1rem;
    font-weight: 600;
    margin: 1.75rem 0 0.75rem;
    color: #343a40;
}

.section-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 2rem;
    padding-top: 1.5rem;
    border-top: 1px solid #dee2e6;
}

/* ── Loading ── */
.settings-loading {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 0;
    color: #6c757d;
}

.spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid #dee2e6;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
    margin-bottom: 1rem;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

/* ── Forms ── */
.form-group {
    margin-bottom: 1.25rem;
}

.form-label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.35rem;
    font-size: 0.9rem;
    color: #343a40;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.15s;
    box-sizing: border-box;
}

.form-control:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.15);
}

textarea.form-control {
    resize: vertical;
}

.field-error {
    color: #dc3545;
    font-size: 0.85rem;
    margin: 0.5rem 0;
}

/* ── Profile ── */
.profile-layout {
    display: grid;
    grid-template-columns: 200px 1fr;
    gap: 2rem;
}

.avatar-area {
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    background: #e9ecef;
    margin: 0 auto 1rem;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    border: 3px solid #dee2e6;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
    color: #adb5bd;
}

/* ── Toggle switches ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-info {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
}

.toggle-label {
    font-weight: 500;
    font-size: 0.95rem;
}

.toggle-desc {
    font-size: 0.85rem;
    color: #6c757d;
}

.switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    top: 0; left: 0; right: 0; bottom: 0;
    background: #ccc;
    transition: 0.3s;
    border-radius: 26px;
}

.slider::before {
    content: "";
    position: absolute;
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background: white;
    transition: 0.3s;
    border-radius: 50%;
}

.switch input:checked + .slider {
    background: #0d6efd;
}

.switch input:checked + .slider::before {
    transform: translateX(22px);
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem 1.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.35rem 0;
    cursor: pointer;
    font-size: 0.95rem;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 0.85rem 1.25rem;
    border: none;
    background: #f8f9fa;
    cursor: pointer;
