}

.btn-outline-danger {
    background: transparent;
    color: #dc3545;
    border-color: #dc3545;
}

.btn-outline-danger:hover {
    background: #dc3545;
    color: white;
}

.btn-sm {
    padding: 0.3rem 0.75rem;
    font-size: 0.8rem;
}

.text-muted {
    color: #6c757d;
}

/* ── Responsive ── */
@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding: 1rem 0 0;
