        overflow-x: auto;
        padding: 0;
    }

    .settings-nav-item {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
        padding: 0.65rem 1rem;
    }

    .settings-nav-item.active {
        border-bottom-color: #0d6efd;
        border-left-color: transparent;
    }

    .settings-content {
        padding: 1.5rem 1rem;
    }

    .profile-layout {
        grid-template-columns: 1fr;
    }

    .appearance-grid {
        grid-template-columns: 1fr;
    }
}

