{"file_text": "@page "/settings"
@using sv_08765451dd404ad6b32f04f2d5a10083.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h3 class="settings-sidebar-title">Settings</h3>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="settings-nav-icon">@section.Value.Icon</span>
                    <span class="settings-nav-label">@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="settings-loading">
                <div class="spinner"></div>
                <p>Loading settings…</p>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }

        @if (_showRevokeDialog)
        {
            <div class="dialog-overlay" @onclick="CancelRevoke">
                <div class="dialog-box" @onclick:stopPropagation="true">
                    <h4>Revoke Session</h4>
                    <p>Are you sure you want to revoke access for this session?</p>
                    <p class="dialog-detail">@_revokeSessionDevice — @_revokeSessionLocation</p>
                    <div class="dialog-actions">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@* ───── Profile Section ───── *@
@code {
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Profile</h2>
            <p class="section-desc">Manage your personal information and public profile.</p>

            <div class="profile-layout">
                <div class="avatar-area">
                    <div class="avatar-preview">
                        @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                        {
                            <img src="@_profileAvatarUrl" alt="Avatar" />
                        }
                        else
                        {
                            <span class="avatar-placeholder">👤</span>
                        }
                    </div>
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control" @bind="_profileAvatarUrl" placeholder="https://example.com/avatar.png" />
                </div>

                <div class="profile-fields">
                    <div class="form-group">
                        <label class="form-label">Display Name</label>
                        <input type="text" class="form-control" @bind="_profileDisplayName" />
                    </div>

                    <div class="form-group">
                        <label class="form-label">Email</label>
                        <input type="email" class="form-control" @bind="_profileEmail" />
                    </div>

                    <div class="form-group">
                        <label class="form-label">Bio</label>
                        <textarea class="form-control" rows="4" @bind="_profileBio"></textarea>
                    </div>
                </div>
            </div>

            <div class="section-actions">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };
}

@* ───── Notifications Section ───── *@
@code {
    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h2>Notifications</h2>
            <p class="section-desc">Choose how and when you'd like to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Email Notifications</span>
                        <span class="toggle-desc">Receive notifications via email</span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" @bind="_notifEmail" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
                        <span class="toggle-label">Push Notifications</span>
                        <span class="toggle-desc">Receive push notifications in your browser</span>
                    </div>
                    <label class="switch">
                        <input type="checkbox" @bind="_notifPush" />
                        <span class="slider"></span>
                    </label>
                </div>

                <div class="toggle-row">
                    <div class="toggle-info">
