.preview-compact .preview-card {
    padding: 0.5rem;
}

.preview-compact .preview-card h5 {
    margin-bottom: 0.25rem;
    font-size: 0.95em;
}

.preview-compact .preview-card p {
    margin-bottom: 0.35rem;
}

